package org.jsoup.nodes;

import org.jsoup.helper.Validate;

/**
 * A PseudoTextElement is a fake {@link Element} that wraps text nodes, so that text nodes can be selected using
 * the normal element selectors.
 */
public class PseudoTextElement extends Element {
    private String text;

    /**
     * Create a new PseudoTextElement.
     * @param text the text to wrap
     */
    public PseudoTextElement(String text) {
        super(Tag.valueOf("#text", ParseSettings.preserveCase), ""); // Use a special tag name for text nodes
        this.text = text;
    }

    @Override
    public String text() {
        return text;
    }

    @Override
    public String ownText() {
        return text;
    }

    @Override
    public Element text(String newText) {
        Validate.notNull(newText);
        this.text = newText;
        return this;
    }

    @Override
    public String nodeName() {
        return "#text";
    }

    @Override
    public String toString() {
        return text;
    }

    @Override
    public String html() {
        return org.jsoup.internal.StringUtil.normaliseWhitespace(text);
    }
}

