private static void addMatchTextElements(Element element, Elements elements) {
    // Split the element's child nodes to extract text nodes between block elements
    java.util.List<org.jsoup.nodes.Node> childNodes = element.childNodes();
    StringBuilder currentText = new StringBuilder();

    for (org.jsoup.nodes.Node node : childNodes) {
        if (node instanceof org.jsoup.nodes.TextNode) {
            // Collect text content
            currentText.append(((org.jsoup.nodes.TextNode) node).getWholeText());
        } else if (node instanceof org.jsoup.nodes.Element) {
            // Found an element, if we have accumulated text, create a PseudoTextElement
            if (currentText.length() > 0) {
                String text = currentText.toString().trim();
                if (!text.isEmpty()) {
                    org.jsoup.nodes.PseudoTextElement pte = new org.jsoup.nodes.PseudoTextElement(text);
                    elements.add(pte);
                }
                currentText.setLength(0); // clear the buffer
            }
            // If this is a <br> element, we may want to create a PseudoTextElement even if text is empty
            // depending on the context
        } else {
            // Other node types (comments, etc.) don't affect text splitting
        }
    }

    // Handle any remaining text after the last element
    if (currentText.length() > 0) {
        String text = currentText.toString().trim();
        if (!text.isEmpty()) {
            org.jsoup.nodes.PseudoTextElement pte = new org.jsoup.nodes.PseudoTextElement(text);
            elements.add(pte);
        }
    }
}

