            org.jsoup.nodes.PseudoTextElement first = pseudoElements.get(0);
            if (structEval.matches(root, first)) {
                result.add(first);
                break; // Only add once
            }
        } else if (structEval instanceof Evaluator.IsLastChild && !pseudoElements.isEmpty()) {
            // Last child is the last element in our list
            org.jsoup.nodes.PseudoTextElement last = pseudoElements.get(pseudoElements.size() - 1);
            if (structEval.matches(root, last)) {
